SELECT fishery_name
FROM fisheries
ORDER BY fishery_name ASC;

SELECT f.fishery_name
FROM fisheries f
WHERE EXISTS (
    SELECT 1 FROM recruitment r WHERE r.fishery_id = f.fishery_id AND r.recruitment_year = 2020 AND r.recruitment_amount > 0
) AND EXISTS (
    SELECT 1 FROM biomass b WHERE b.fishery_id = f.fishery_id AND b.biomass_year = 2020 AND b.biomass_amount > 0
) AND EXISTS (
    SELECT 1 FROM cash_flow cf WHERE cf.fishery_id = f.fishery_id AND cf.cash_flow_year = 2020 AND cf.average_cash_flow > 0
) AND EXISTS (
    SELECT 1 FROM effort e WHERE e.fishery_id = f.fishery_id AND e.effort_year = 2020 AND e.total_effort > 0
)
ORDER BY f.fishery_name;

SELECT SUM(total_effort) AS total_effort_2020
FROM effort
WHERE effort_year = 2020;

SELECT species_name
FROM species
WHERE average_weight = (SELECT MAX(average_weight) FROM species);

SELECT SUM(landing_amount) AS total_landing_amount
FROM landings
WHERE species_id = 1 AND landing_year = 2020;

SELECT biomass_value
FROM biomass
WHERE fishery_id = 1 AND biomass_year = 2020;

SELECT average_cash_flow
FROM cash_flow
WHERE fishery_id = 1 AND cash_flow_year = 2020;

SELECT SUM(total_effort) AS total_effort
FROM effort
WHERE fishery_id = 0 AND effort_year = 2020;

SELECT species_id, landing_amount
FROM landings
WHERE landing_year = 2020;

SELECT SUM(landing_amount) AS total_landing_amount
FROM landings
WHERE species_id = 1;

SELECT SUM(biomass_amount) AS total_biomass
FROM biomass_records
WHERE species_id = 1 AND biomass_year = 2019;

SELECT MAX(biomass_amount) AS max_biomass
FROM biomass
WHERE species_id = 1 AND biomass_year = 2019;

SELECT MAX(biomass_amount) AS max_biomass
FROM biomass_records
WHERE species_id = 1 AND biomass_year = 2019;

SELECT fishery_name
FROM fisheries
WHERE last_inspection_date = (SELECT MAX(last_inspection_date) FROM fisheries);

SELECT SUM(landing_amount) AS total_harvest
FROM landings
WHERE species_id = 1 AND landing_year = 2020;

SELECT COUNT(*) AS permit_required_count
FROM fisheries
WHERE permit_required = 1;

SELECT SUM(recruitment_amount) AS total_recruitment
FROM recruitment
WHERE species_id = 1 AND recruitment_year = 2020;

SELECT fishery_name, last_inspection_date
FROM fisheries
ORDER BY last_inspection_date DESC;
